const body = $input.first().json.body || $input.first().json;
const session = body.data?.object || {};
const email = (session.customer_details?.email || session.customer_email || '').toLowerCase();
const name = session.customer_details?.name || '';
const amount_cents = session.amount_total || 0;
const session_id = session.id || '';
const payment_link_id = session.payment_link || '';
if (!email) return [];
return [{json:{email, name, amount_cents, amount_euros: amount_cents/100, session_id, payment_link_id}}];

const item = $input.first().json;
const map = {
  9700:  {name:'Templates Pack', next_action:'send_templates'},
  14700: {name:'Automation Audit', next_action:'send_calendly'},
  19700: {name:'Monthly Maintenance', next_action:'send_onboarding'},
  29700: {name:'n8n Autonomy Training', next_action:'send_training'},
  49700: {name:'Starter Pack', next_action:'send_onboarding'},
  79700: {name:'Growth Retainer', next_action:'send_onboarding_priority'},
  149700:{name:'Scale Pack', next_action:'send_onboarding'}
};
const p = map[item.amount_cents] || {name:'Unknown Product', next_action:'manual_review'};
return [{json:{...item, product_name:p.name, next_action:p.next_action}}];

const item = $input.first().json;
const firstName = (item.name || '').split(' ')[0] || 'there';
const emails = {
  send_calendly:{subject:'Your Automation Audit is booked',body:'Hi '+firstName+', thank you!'},
  send_templates:{subject:'Your Templates Pack is ready',body:'Hi '+firstName+', your workflows are ready.'},
  send_onboarding:{subject:'Welcome aboard - '+item.product_name,body:'Hi '+firstName+', thank you for choosing '+item.product_name+'!'}
};
const e = emails[item.next_action] || {subject:'Thank you',body:'Hi '+firstName+', thank you for your purchase.'};
return [{json:{...item, email_subject: e.subject, email_body: e.body}}];
